startup:
export SDKMAN_DIR=$HOME/.sdkman;

if [[ -d .git ]] && [[ "{{AUTO_UPDATE}}" == "1" ]]; then git pull; fi;

source "$SDKMAN_DIR/bin/sdkman-init.sh" || true;

if [[ ! -z "{{KOTLIN_VERSION}}" ]]; then
    sdk install kotlin {{KOTLIN_VERSION}} || sdk use kotlin {{KOTLIN_VERSION}};
fi;

cd /mnt/server;

if [[ -f build.gradle.kts ]] || [[ -f build.gradle ]]; then
    echo "Gradle Kotlin project detected";
    ./gradlew build || gradle build;
    java -jar build/libs/*.jar;
elif [[ -f pom.xml ]]; then
    echo "Maven Kotlin project detected";
    mvn package;
    java -jar target/*.jar;
elif [[ -f {{KOTLIN_FILE}} ]]; then
    echo "Running Kotlin script";
    kotlinc -script {{KOTLIN_FILE}};
else
    echo "No build system detected, running fallback JAR";
    java -jar {{JAR_FILE}};
fi
